# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
import uuid
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)

# Mock database to store user email and reset tokens
reset_db = {}

@app.route('/request_reset', methods=['POST'])
def request_password_reset():
    data = request.get_json()
    email = data.get('email')

    if not email:
        return jsonify({'error': 'Email is required'}), 400

    token = str(uuid.uuid4())
    reset_db[email] = token
    reset_url = f"http://yourdomain.com/reset?token={token}"

    send_reset_email(email, reset_url)

    return jsonify({'message': 'Reset link sent successfully'}), 200

def send_reset_email(email, reset_url):
    msg = MIMEText(f'Click the following link to reset your password: {reset_url}')
    msg['Subject'] = 'Password Reset Request'
    msg['From'] = 'your-email@example.com'
    msg['To'] = email

    with smtplib.SMTP('smtp.example.com', 587) as server:
        server.starttls()
        server.login('your-email@example.com', 'your-password')
        server.sendmail('your-email@example.com', email, msg.as_string())

if __name__ == '__main__':
    app.run(debug=True)